// Default samples encoded as base64 WAV
// Kick: DD_BWJAZZ_kick_one_shot_medium.wav
// Snare: BB3_snare_snake.wav

export const KICK_B64 = "";

export const SNARE_B64 = "";

export const DEFAULT_SAMPLES = { kick: KICK_B64, snare: SNARE_B64 };

export const b64toAB = (b64) => {
  const bin = atob(b64);
  const buf = new ArrayBuffer(bin.length);
  const view = new Uint8Array(buf);
  for (let i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i);
  return buf;
};
